import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:3001';

function App() {
    // State
    const [amount, setAmount] = useState('');
    const [receiver, setReceiver] = useState('');
    const [currency, setCurrency] = useState('AED');
    const [fxRate, setFxRate] = useState(28.5);
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState('');
    const [transactionId, setTransactionId] = useState(null);
    const [feeBreakdown, setFeeBreakdown] = useState(null);
    const [ledger, setLedger] = useState([]);
    const [stats, setStats] = useState(null);
    const [selectedTx, setSelectedTx] = useState(null);
    const [connected, setConnected] = useState(false);

    // Check health on mount
    useEffect(() => {
        checkHealth();
        fetchLedger();
        fetchStats();
        const interval = setInterval(fetchLedger, 5000);
        return () => clearInterval(interval);
    }, []);

    const checkHealth = async () => {
        try {
            const res = await axios.get(`${API_URL}/api/health`);
            setConnected(res.data.corda_connected);
            console.log('✅ Connected to backend');
        } catch (err) {
            console.error('❌ Backend not reachable');
            setConnected(false);
        }
    };

    const fetchLedger = async () => {
        try {
            const res = await axios.get(`${API_URL}/api/corda/vault`);
            setLedger(res.data.data.states || []);
        } catch (err) {
            console.error('Failed to fetch ledger');
        }
    };

    const fetchStats = async () => {
        try {
            const res = await axios.get(`${API_URL}/api/corda/stats`);
            setStats(res.data.data);
        } catch (err) {
            console.error('Failed to fetch stats');
        }
    };

    const handleSend = async (e) => {
        e.preventDefault();
        if (!amount || !receiver) {
            setStatus('❌ Please fill in all fields');
            return;
        }

        setLoading(true);
        setStatus('⏳ Processing transaction...');
        setFeeBreakdown(null);
        setTransactionId(null);

        try {
            const response = await axios.post(`${API_URL}/api/send`, {
                amount: parseFloat(amount),
                currency: currency,
                receiver: receiver,
                fxRate: fxRate
            });

            if (response.data.success) {
                setTransactionId(response.data.transactionId);
                setFeeBreakdown(response.data.feeBreakdown);
                setStatus(`✅ Transaction confirmed on blockchain! TX: ${response.data.transactionId}`);
                await fetchLedger();
                await fetchStats();
            } else {
                setStatus(`❌ Transaction failed: ${response.data.error}`);
            }
        } catch (err) {
            setStatus(`❌ Error: ${err.message}`);
        } finally {
            setLoading(false);
        }
    };

    const fetchTransaction = async (txId) => {
        try {
            const res = await axios.get(`${API_URL}/api/corda/transaction/${txId}`);
            setSelectedTx(res.data.data);
        } catch (err) {
            setSelectedTx(null);
        }
    };

    return (
        <div className="container">
            <div className="header">
                <h1>💸 RemitChain</h1>
                <span style={{ color: connected ? '#48bb78' : '#fc8181' }}>
                    {connected ? '🟢 Blockchain Connected' : '🔴 Disconnected'}
                </span>
            </div>

            {/* Stats Dashboard */}
            {stats && (
                <div className="stats-grid">
                    <div className="stat-card">
                        <div className="stat-value">{stats.totalTransactions}</div>
                        <div className="stat-label">Total Transactions</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-value">৳{stats.totalVolume?.toFixed(0) || 0}</div>
                        <div className="stat-label">Total Volume (BDT)</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-value">৳{stats.totalFeeCollected?.toFixed(2) || 0}</div>
                        <div className="stat-label">Total Fees Collected</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-value">৳{stats.totalProfit?.toFixed(2) || 0}</div>
                        <div className="stat-label">Your Profit</div>
                    </div>
                </div>
            )}

            {/* Send Money Form */}
            <div className="card">
                <h2>Send Money</h2>
                <p style={{ color: '#4a5568', marginBottom: 16 }}>
                    Fee: 1.7% (0.7% bank fee, 1.0% tech fee)
                </p>

                <form onSubmit={handleSend}>
                    <label>Amount</label>
                    <input
                        type="number"
                        value={amount}
                        onChange={(e) => setAmount(e.target.value)}
                        placeholder="Enter amount"
                        disabled={loading}
                        required
                    />

                    <label>Currency</label>
                    <select value={currency} onChange={(e) => setCurrency(e.target.value)} disabled={loading}>
                        <option value="AED">AED</option>
                        <option value="USD">USD</option>
                        <option value="SAR">SAR</option>
                    </select>

                    <label>Receiver bKash Number</label>
                    <input
                        type="text"
                        value={receiver}
                        onChange={(e) => setReceiver(e.target.value)}
                        placeholder="+8801712345678"
                        disabled={loading}
                        required
                    />

                    <label>Exchange Rate (AED → BDT)</label>
                    <input
                        type="number"
                        value={fxRate}
                        onChange={(e) => setFxRate(parseFloat(e.target.value))}
                        step="0.01"
                        disabled={loading}
                    />

                    <button type="submit" className="btn" disabled={loading}>
                        {loading ? 'Processing...' : '💰 Send Money'}
                    </button>
                </form>

                {status && (
                    <div className={`status ${status.includes('✅') ? 'status-success' : 'status-error'}`}>
                        {status}
                    </div>
                )}

                {transactionId && (
                    <div className="status status-success">
                        <strong>Transaction ID:</strong> {transactionId}
                        <br />
                        <button
                            className="btn"
                            style={{ marginTop: 8, padding: '6px 12px', fontSize: 14 }}
                            onClick={() => fetchTransaction(transactionId)}
                        >
                            🔍 View Transaction
                        </button>
                    </div>
                )}

                {selectedTx && (
                    <div className="card" style={{ marginTop: 12 }}>
                        <h4>Transaction Details</h4>
                        <pre style={{ background: '#f7fafc', padding: 12, borderRadius: 8, fontSize: 12, overflow: 'auto' }}>
                            {JSON.stringify(selectedTx, null, 2)}
                        </pre>
                        <button className="btn" style={{ marginTop: 8, padding: '6px 12px', fontSize: 14 }} onClick={() => setSelectedTx(null)}>
                            Close
                        </button>
                    </div>
                )}
            </div>

            {/* Fee Breakdown */}
            {feeBreakdown && (
                <div className="card">
                    <h3>Fee Breakdown</h3>
                    <div className="fee-grid">
                        <div className="fee-item">
                            <div className="label">Amount</div>
                            <div className="value">{amount} {currency}</div>
                        </div>
                        <div className="fee-item">
                            <div className="label">Converted (BDT)</div>
                            <div className="value">৳{feeBreakdown.bdtAmount.toFixed(2)}</div>
                        </div>
                        <div className="fee-item">
                            <div className="label">Receiver Gets</div>
                            <div className="value">৳{feeBreakdown.receiverGets.toFixed(2)}</div>
                        </div>
                        <div className="fee-item">
                            <div className="label">Total Fee (1.7%)</div>
                            <div className="value">৳{feeBreakdown.totalFee.toFixed(2)}</div>
                        </div>
                        <div className="fee-item">
                            <div className="label">Bank Fee (0.7%)</div>
                            <div className="value">৳{feeBreakdown.bankFees.toFixed(2)}</div>
                        </div>
                        <div className="fee-item">
                            <div className="label">Your Profit (0.6%)</div>
                            <div className="value">৳{feeBreakdown.yourProfit.toFixed(2)}</div>
                        </div>
                    </div>
                </div>
            )}

            {/* Ledger (Blockchain View) */}
            <div className="card">
                <h3>📊 Blockchain Ledger</h3>
                <p style={{ color: '#4a5568', fontSize: 14, marginBottom: 12 }}>
                    {ledger.length} transactions recorded on the blockchain
                </p>
                {ledger.length === 0 ? (
                    <p style={{ color: '#a0aec0', textAlign: 'center', padding: 20 }}>
                        No transactions yet. Send money to see it appear on the blockchain!
                    </p>
                ) : (
                    <div style={{ overflowX: 'auto' }}>
                        <table className="ledger-table">
                            <thead>
                                <tr>
                                    <th>TX ID</th>
                                    <th>Amount</th>
                                    <th>Receiver</th>
                                    <th>Fee</th>
                                    <th>Status</th>
                                    <th>Time</th>
                                    <th>Action</th>
                                </tr>
                            </thead>
                            <tbody>
                                {ledger.map((item) => (
                                    <tr key={item.id}>
                                        <td><strong>{item.id}</strong></td>
                                        <td>{item.amount} {item.currency}</td>
                                        <td>{item.receiver}</td>
                                        <td>৳{item.fee?.toFixed(2) || 0}</td>
                                        <td>
                                            <span className="badge badge-success">
                                                {item.status || 'CONFIRMED'}
                                            </span>
                                        </td>
                                        <td>{new Date(item.timestamp).toLocaleTimeString()}</td>
                                        <td>
                                            <button
                                                className="btn"
                                                style={{ padding: '4px 10px', fontSize: 12 }}
                                                onClick={() => fetchTransaction(item.id)}
                                            >
                                                View
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* Footer */}
            <div style={{ textAlign: 'center', padding: 20, color: '#a0aec0', fontSize: 14 }}>
                RemitChain Mock Blockchain Demo v1.0 | {new Date().getFullYear()}
            </div>
        </div>
    );
}

export default App;
